import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { useSelector } from 'react-redux';
import { toast } from 'react-toastify';

function TakeTest() {
  const { id } = useParams();
  const navigate = useNavigate();
  const user = useSelector((state) => state.auth.user);
  const [test, setTest] = useState(null);
  const [answers, setAnswers] = useState({});

  useEffect(() => {
    if (user?.role === "student") {
      fetch(`http://localhost:3001/tests/${id}`)
        .then((res) => res.json())
        .then((data) => setTest(data))
        .catch((error) => {
          console.error("Test fetch error:", error);
          toast.error("Ошибка загрузки теста");
          navigate("/courses");
        });
    } else {
      navigate("/courses");
    }
  }, [id, user, navigate]);

  const handleAnswerChange = (questionId, value) => {
    setAnswers((prev) => ({ ...prev, [questionId]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const result = {
      testId: parseInt(id),
      userId: user.id,
      answers: Object.entries(answers).map(([questionId, answer]) => ({ questionId: parseInt(questionId), answer })),
      score: 0, // Calculate score on server side
      submittedAt: new Date().toISOString(),
    };
    try {
      const response = await fetch("http://localhost:3001/test_results", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(result),
      });
      if (response.ok) {
        toast.success("Тест отправлен!");
        navigate("/courses");
      } else {
        toast.error("Ошибка отправки теста");
      }
    } catch (error) {
      console.error("Test submit error:", error);
      toast.error("Сетевая ошибка при отправке теста");
    }
  };

  if (!test) return <div className="container mt-5"><h1>Загрузка...</h1></div>;

  return (
    <div className="container mt-5">
      <h1 className="text-center mb-4">{test.title}</h1>
      <div className="card shadow">
        <div className="card-body">
          <form onSubmit={handleSubmit}>
            {test.questions && test.questions.map((question) => (
              <div key={question.id} className="mb-3">
                <label className="form-label">{question.text}</label>
                <input
                  type="text"
                  className="form-control"
                  value={answers[question.id] || ''}
                  onChange={(e) => handleAnswerChange(question.id, e.target.value)}
                />
              </div>
            ))}
            <button type="submit" className="btn btn-primary w-100">Отправить</button>
          </form>
        </div>
      </div>
    </div>
  );
}

export default TakeTest;
